import React, { useState } from "react";
import { useLocation } from "react-router-dom";

const AIInteractionPage = () => {
    const location = useLocation();
    const { avatar, mode } = location.state || { avatar: null, mode: "interaction" };

    // State for chatbot conversation
    const [messages, setMessages] = useState([]);
    const [userInput, setUserInput] = useState("");

    // Function to handle message submission
    const handleSendMessage = () => {
        if (!userInput.trim()) return;

        // Add user message to the chat
        setMessages((prev) => [...prev, { sender: "user", text: userInput }]);

        // Simulate AI response
        setTimeout(() => {
            setMessages((prev) => [...prev, { sender: "ai", text: "Hello! How can I assist you today?" }]);
        }, 1000);

        setUserInput(""); // Clear input field
    };

    return (
        <div style={{ textAlign: "center", padding: "20px", height: "100vh", display: "flex", flexDirection: "column" }}>
            {/* Page Title (Interaction or Health Check-In) */}
            <h1 style={{ marginBottom: "10px" }}>
                {mode === "interaction" ? "Interaction Mode" : "Health Check-In"}
            </h1>

            {/* Avatar Display (Twice the previous size) */}
            <div style={{ flex: "0 0 60%", display: "flex", justifyContent: "center", alignItems: "center" }}>
                {avatar && avatar.video ? (
                    <video
                        src={avatar.video}
                        autoPlay
                        loop
                        muted
                        style={{
                            maxHeight: "80%",
                            maxWidth: "80%",
                            borderRadius: "15px",
                        }}
                    />
                ) : (
                    <img
                        src={avatar?.image}
                        alt={avatar?.name}
                        style={{
                            maxHeight: "80%",
                            maxWidth: "80%",
                            objectFit: "contain",
                            borderRadius: "15px",
                        }}
                    />
                )}
            </div>

            {/* Chatbot Interface (Smaller Size) */}
            <div style={{ flex: "0 0 15%", padding: "10px", display: "flex", flexDirection: "column", justifyContent: "space-between" }}>
                <div
                    style={{
                        flex: 1,
                        overflowY: "auto",
                        border: "1px solid #ccc",
                        borderRadius: "8px",
                        padding: "6px",
                        marginBottom: "6px",
                        backgroundColor: "#f9f9f9",
                        fontSize: "12px", // Smaller text size
                        height: "80px", // Reducing chatbox height
                    }}
                >
                    {messages.map((msg, index) => (
                        <div
                            key={index}
                            style={{
                                textAlign: msg.sender === "user" ? "right" : "left",
                                marginBottom: "5px",
                            }}
                        >
                            <span
                                style={{
                                    display: "inline-block",
                                    padding: "4px 8px",
                                    borderRadius: "8px",
                                    backgroundColor: msg.sender === "user" ? "#d1e7dd" : "#e9ecef",
                                    fontSize: "12px", // Smaller chat bubble
                                }}
                            >
                                {msg.text}
                            </span>
                        </div>
                    ))}
                </div>
                <div style={{ display: "flex", gap: "5px" }}>
                    <input
                        type="text"
                        value={userInput}
                        onChange={(e) => setUserInput(e.target.value)}
                        placeholder="Type your message..."
                        style={{
                            flex: 1,
                            padding: "6px",
                            borderRadius: "8px",
                            border: "1px solid #ccc",
                            fontSize: "12px",
                        }}
                    />
                    <button
                        onClick={handleSendMessage}
                        style={{
                            padding: "6px 12px",
                            borderRadius: "8px",
                            backgroundColor: "#007bff",
                            color: "white",
                            fontSize: "12px",
                            cursor: "pointer",
                            border: "none",
                        }}
                    >
                        Send
                    </button>
                </div>
            </div>
        </div>
    );
};

export default AIInteractionPage;
